mapper.select:
SELECT r.*, c.category_name as categoryName FROM report_definition r LEFT JOIN report_category c ON r.category_id = c.id WHERE r.status = 'ACTIVE'
AND (r.report_name LIKE CONCAT('%', #{keyword}, '%') OR r.report_code LIKE CONCAT('%', #{keyword}, '%'))
AND r.report_type = #{reportType}
AND r.category_id = #{categoryId}
ORDER BY r.created_at DESC
